from flask import Flask, request, jsonify
from flask_login import LoginManager, UserMixin, login_user, logout_user, login_required
from werkzeug.security import check_password_hash
from otpauth import OtpAuth

app = Flask(__name__)
app.secret_key = "strong_secret_key"
login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin):
    def __init__(self, id, username, password_hash, mfa_enabled=False, otp_secret=None):
        self.id = id
        self.username = username
        self.password_hash = password_hash
        self.mfa_enabled = mfa_enabled
        self.otp_secret = otp_secret if mfa_enabled else None

users = [User(1, "test", "password_hash", mfa_enabled=True, otp_secret="random_secret")]

@login_manager.user_loader
def load_user(user_id):
    for user in users:
        if user.id == int(user_id):
            return user
    return None

@app.route("/api/login", methods=["POST"])
def login_api():
    username = request.json.get("username")
    password = request.json.get("password")
    otp = request.json.get("otp")

    for user in users:
        if user.username == username:
            if check_password_hash(user.password_hash, password):
                if user.mfa_enabled:
                    auth = OtpAuth(user.otp_secret)
                    if auth.valid_totp(otp):
                        login_user(user)
                        return jsonify({"message": "Logged in successfully"}), 200
                    else:
                        return jsonify({"message": "Incorrect OTP"}), 400
                else:
                    login_user(user)
                    return jsonify({"message": "Logged in successfully"}), 200
            else:
                return jsonify({"message": "Incorrect password"}), 400
    return jsonify({"message": "User not found"}), 404

@app.route("/api/direct-login", methods=["POST"])
def direct_login_api():
    username = request.json.get("username")
    password = request.json.get("password")
    
    for user in users:
        if user.username == username:
            if check_password_hash(user.password_hash, password):
                login_user(user)
                return jsonify({"message": "Logged in successfully"}), 200
            else:
                return jsonify({"message": "Incorrect password"}), 400
    return jsonify({"message": "User not found"}), 404

if __name__ == "__main__":
    app.run(port=8000, debug=True)